33	func (kc *KubeletConfig) create(parameters ...string) {
34		allParams := []string{"--ignore-unknown-parameters=true", "-f", kc.template,
35			"-p", "NAME=" + kc.name}
36		allParams = append(allParams, parameters...)
37		exutil.CreateClusterResourceFromTemplate(kc.oc, allParams...)
38	}
