40	func (kc KubeletConfig) waitUntilSuccess(timeout string) {
41		logger.Infof("wait for %s to report success", kc.name)
42		o.EventuallyWithOffset(1, &kc, timeout, "2s").Should(o.SatisfyAll(
43			HaveConditionField("Success", "status", "True"),
44			HaveConditionField("Success", "message", "Success"),
45		), "KubeletConfig '%s' should report Success in status.conditions, but the current status is not success", kc.GetName())
46	}
47	
48	func (kc KubeletConfig) waitUntilFailure(expectedMsg, timeout string) {
49		logger.Infof("wait for %s to report failure", kc.name)
50		o.EventuallyWithOffset(1, &kc, timeout, "2s").Should(o.SatisfyAll(
51			HaveConditionField("Failure", "status", "True"),
52			HaveConditionField("Failure", "message", o.ContainSubstring(expectedMsg)),
53		), "KubeletConfig '%s' should report Failure in status.conditions and report failure message %s. But it doesn't.", kc.GetName(), expectedMsg)
54	}
