56	// GetGeneratedMCName returns the name of the MC that was generated by this KubeletConfig resource
57	func (kc KubeletConfig) GetGeneratedMCName() (string, error) {
58		mcName, err := kc.Get(`{.metadata.finalizers[0]}`)
59		if err != nil {
60			return "", err
61		}
62		if mcName == "" {
63			return "", fmt.Errorf("it was not possible to get the finalizer from %s %s: %s", kc.GetKind(), kc.GetName(), kc.PrettyString())
64		}
65		return mcName, nil
66	}
67	
68	// GetGeneratedMCNameOrFail returns the name of the MC that was generated by this KubeletConfig resource and fails the test case if it cannot be done
69	func (kc KubeletConfig) GetGeneratedMCNameOrFail() string {
70		mcName, err := kc.GetGeneratedMCName()
71		o.Expect(err).NotTo(o.HaveOccurred(), "Error getting the generated MC for %s %s", kc.GetKind(), kc.GetName())
72		return mcName
73	}
